/**
 * Deferred-Debt Marker parsing — shared lib
 *
 * The counterpart to the YAGNI gate: the gate PREVENTS over-engineering,
 * these markers RECORD the deliberate under-engineering you chose, plus the
 * condition that should make you revisit it. Consumed by:
 *   - posttool/write/debt-marker-tracker (capture on write)
 *   - instructions-loaded/debt-surfacer  (surface at session start)
 *
 * Marker grammar (an inline code comment):
 *   <leader> ork-debt: <choice>, upgrade to <path>, when <trigger>
 * where <leader> is //, #, --, ; or a block-comment leader, and the
 * `upgrade to` / `when` clauses are optional (best-effort parse).
 *
 * The marker token is assembled from parts so THIS source file — and the
 * hooks that import it — are never themselves picked up as debt entries by a
 * repo grep (the same trick stale-import-detector uses for its suppression
 * marker, built from fragments to dodge self-matching).
 */

// Assembled token: never appears as a literal substring in this codebase.
export const DEBT_TOKEN = ['ork', 'debt'].join('-');

// Comment leaders across common languages: // # -- ; and block-comment * //*
const LEADER = String.raw`(?:\/\/|#|--|;|\/\*|\*)`;

/** Matches a single marker comment; capture group 1 is everything after the colon. */
export const DEBT_MARKER_RE = new RegExp(`${LEADER}\\s*${DEBT_TOKEN}:\\s*(.+)`, 'i');

export interface DebtMarker {
  /** The deliberate simplification that was chosen. */
  choice: string;
  /** The upgrade path to take later (optional). */
  upgrade?: string;
  /** The condition that should trigger the upgrade (optional). */
  trigger?: string;
  /** The raw matched marker text. */
  raw: string;
}

/**
 * Parse a single line of text for a debt marker. Returns null if the line
 * holds no marker. The `upgrade to` and `when` clauses are optional — a bare
 * `ork-debt: <choice>` is valid but degrades to a plain TODO (no trigger).
 */
export function parseDebtComment(text: string): DebtMarker | null {
  const m = text.match(DEBT_MARKER_RE);
  if (!m) return null;

  // Strip a trailing block-comment close if present.
  let rest = m[1].replace(/\*\/\s*$/, '').trim();
  if (!rest) return null;

  let choice = rest;
  let upgrade: string | undefined;
  let trigger: string | undefined;

  // Split off ", when <trigger>" first (it always trails).
  const whenIdx = rest.search(/,\s*when\s+/i);
  if (whenIdx !== -1) {
    trigger = rest.slice(whenIdx).replace(/^,\s*when\s+/i, '').trim() || undefined;
    rest = rest.slice(0, whenIdx).trim();
  }

  // Then ", upgrade to <path>".
  const upIdx = rest.search(/,\s*upgrade to\s+/i);
  if (upIdx !== -1) {
    upgrade = rest.slice(upIdx).replace(/^,\s*upgrade to\s+/i, '').trim() || undefined;
    choice = rest.slice(0, upIdx).trim();
  } else {
    choice = rest;
  }

  if (!choice) return null;
  return { choice, upgrade, trigger, raw: m[0].trim() };
}

/** Scan a block of text line-by-line for all debt markers it contains. */
export function scanTextForDebt(text: string): DebtMarker[] {
  const out: DebtMarker[] = [];
  for (const line of text.split('\n')) {
    const parsed = parseDebtComment(line);
    if (parsed) out.push(parsed);
  }
  return out;
}

/** Render one marker as a compact single line for advisories/ledgers. */
export function formatDebtMarker(m: DebtMarker): string {
  const up = m.upgrade ? ` -> ${m.upgrade}` : '';
  const tr = m.trigger ? ` (when ${m.trigger})` : ' (no trigger: just a TODO)';
  return `${m.choice}${up}${tr}`;
}
